mapper.select:
SELECT id, semester_code, semester_name, academic_year, semester_type, start_date, end_date, is_current, status, description, created_at FROM semesters WHERE deleted = 0
AND semester_code LIKE CONCAT('%', #{query.semesterCode}, '%')
AND semester_name LIKE CONCAT('%', #{query.semesterName}, '%')
AND academic_year = #{query.academicYear}
AND semester_type = #{query.semesterType}
AND status = #{query.status}
ORDER BY academic_year DESC, semester_type
